Action.Str:
var raw = global('RZ_GLOBAL') || '{}';
var g = {};
try { g = JSON.parse(raw); } catch(e) { g = {}; }
var MODES  = {0:'ARRET',1:'VEILLE',2:'FIXE',3:'DEPLACEMENT',4:'AUTONOME',5:'ERREUR'};
var PTGE   = {0:'Ecran',1:'Vocal',2:'Manette',3:'Laisse',4:'Laisse+Vocal'};
var modeVal = g.CfgS ? (g.CfgS.modeRZ  !== undefined ? g.CfgS.modeRZ  : '?') : '?';
var ptgeVal = g.CfgS ? (g.CfgS.typePtge !== undefined ? g.CfgS.typePtge : '?') : '?';
var reseau  = g.CfgS ? (g.CfgS.typeReseau || '?') : '?';
setGlobal('RZetatMode',     MODES[modeVal] || ('Mode '+modeVal));
setGlobal('RZetatPtge',     PTGE[ptgeVal]  || ('Ptge '+ptgeVal));
setGlobal('RZetatReseau',   reseau);
setGlobal('RZetatIpSE',     (g.Sys && g.Sys.ipSE) ? g.Sys.ipSE : '192.168.1.12');
var ipSP = '?';
if      (reseau==='WifiInternetBox') ipSP='192.168.1.40 (local)';
else if (reseau==='Wifi4KSP')        ipSP='DuckDNS (4G SP)';
else if (reseau==='WifiSPSsI')       ipSP='SP Smart local';
else if (reseau==='4K')              ipSP='DuckDNS (SIM SE)';
setGlobal('RZetatIpSP', ipSP);
var CTX = {
    'WifiInternetBox':'Wi-Fi box maison - SP RPI local',
    'Wifi4KSP':       'Wi-Fi partage SP - SP RPI DuckDNS',
    'WifiSPSsI':      'Wi-Fi SP sans internet - SP Smart local',
    '4K':             'SIM SE - SP RPI via DuckDNS'
};
setGlobal('RZetatCtxReseau', CTX[reseau] || reseau);
var d = new Date();
setGlobal('RZetatTs', d.getHours()+':'+('0'+d.getMinutes()).slice(-2)+':'+('0'+d.getSeconds()).slice(-2));
performTask('RZ_EtatMajScene', 5);
performTask('RZ_EtatRefresh', 5);
